const goldData = await helpers.httpRequest({
  method: 'GET',
  url: 'https://data-asg.goldprice.org/dbXRates/USD'
});

const hargaUSDPerTroyOz = goldData.items[0].xauPrice;
const kursUSDIDR = 16500;
const hargaIDRPerGram = (hargaUSDPerTroyOz / 31.1035) * kursUSDIDR;

return "Harga emas hari ini: Rp " + Math.round(hargaIDRPerGram).toLocaleString('id-ID') + " per gram";

let input = {};
try {
  input = JSON.parse(query);
} catch(e) {
  // coba parse sebagai string
  const match = query.match(/\{.*\}/s);
  if (match) {
    try { input = JSON.parse(match[0]); } catch(e2) {}
  }
}

const result = await helpers.httpRequest({
  method: 'POST',
  url: 'http://gadai-dashboard:3000/api/transaction',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    nama_user: input.nama_user || 'Unknown',
    jenis_barang: input.jenis_barang || 'emas',
    pertanyaan_user: input.pertanyaan_user || '',
    nama_barang: input.nama_barang || '',
    estimasi_nilai: input.estimasi_nilai || 0,
    wilayah: input.wilayah || '',
    gramasi: input.gramasi || null,
    channel: 'Telegram'
  })
});

return "Data berhasil disimpan ke dashboard dengan ID: " + result.id;
